parameters.jsCode:
const accounts = $input.all().map(i=>i.json);
const candidates = accounts.filter(a => {
  const health = parseInt(a.health_score||0,10);
  const nps = parseInt(a.nps_score||0,10);
  const tenure = parseInt(a.tenure_months||0,10);
  return health >= 80 && nps >= 8 && tenure >= 3 && a.contact_email;
}).sort((a,b)=>parseInt(b.mrr||0)-parseInt(a.mrr||0)).slice(0,5);
return candidates.map(c=>({json:c}));

