parameters.jsCode:
const candidates = $('Identify Candidates').all().map(i=>i.json);
const drafts = $input.all();
const list = candidates.map((c,i) => {
  let email = {};
  try { email = JSON.parse((drafts[i]?.json?.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch {}
  return { ...c, draft_subject: email.subject, draft_body: email.body };
});
return [{ json: { date: new Date().toISOString().slice(0,10), total_candidates: list.length, candidates: list } }];

